import { useState, useEffect } from "react";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import Leaderboard from "./components/Leaderboard";
import AddEntry from "./components/AddEntry";
import RemoveEntry from "./components/RemoveEntry";
import StatsPanel from "./components/StatsPanel";
import PerformancePanel from "./components/PerformancePanel";
import HistoryPanel from "./components/HistoryPanel";
import { getLeaderboard, getInfo } from "./api/leaderboard";

const queryClient = new QueryClient();

function HeroSection({ setActiveTab }) {
  const [totalPlayers, setTotalPlayers] = useState(0);
  const [topScore, setTopScore] = useState(0);
  const [topPlayer, setTopPlayer] = useState("—");

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const lb = await getLeaderboard();
        const info = await getInfo();
        const entries = lb.data.leaderboard;
        if (entries.length > 0) {
          setTopScore(entries[0].score.toLocaleString());
          setTopPlayer(entries[0].username);
        }
        setTotalPlayers(info.data.stats.totalEntries || 0);
      } catch (e) {}
    };
    fetchStats();
    const interval = setInterval(fetchStats, 5000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="relative overflow-hidden bg-gray-950">
      {/* Animated grid background */}
      <div className="absolute inset-0 bg-[linear-gradient(rgba(255,255,255,0.03)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.03)_1px,transparent_1px)] bg-[size:50px_50px]" />

      {/* Glow effects */}
      <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[600px] h-[300px] bg-yellow-500/10 rounded-full blur-3xl" />
      <div className="absolute top-10 left-1/4 w-[200px] h-[200px] bg-orange-500/10 rounded-full blur-2xl" />
      <div className="absolute top-10 right-1/4 w-[200px] h-[200px] bg-red-500/10 rounded-full blur-2xl" />

      <div className="relative px-6 pt-14 pb-10 text-center">
        {/* Badge */}
        <div className="inline-flex items-center gap-2 bg-yellow-500/10 border border-yellow-500/30 rounded-full px-4 py-1.5 text-yellow-400 text-xs font-medium mb-6">
          <span className="w-2 h-2 bg-yellow-400 rounded-full animate-ping inline-block" />
          LIVE LEADERBOARD
        </div>

        {/* Title */}
        <h1 className="text-5xl font-black mb-3 leading-tight">
          <span className="bg-gradient-to-r from-yellow-400 via-orange-400 to-red-500 bg-clip-text text-transparent">
            Dynamic
          </span>
          <br />
          <span className="text-white">Leaderboard System</span>
        </h1>

        <p className="text-gray-400 text-base mb-10 max-w-md mx-auto">
          Real-time rankings • Score velocity tracking • Live statistics
        </p>

        {/* Live Stats Cards */}
        <div className="flex justify-center gap-4 flex-wrap mb-10">
          <div className="bg-gray-900/80 backdrop-blur border border-gray-800 rounded-2xl px-6 py-4 min-w-[140px]">
            <p className="text-gray-500 text-xs mb-1">Total Players</p>
            <p className="text-3xl font-black text-yellow-400">{totalPlayers}</p>
          </div>
          <div className="bg-gray-900/80 backdrop-blur border border-gray-800 rounded-2xl px-6 py-4 min-w-[140px]">
            <p className="text-gray-500 text-xs mb-1">Top Score</p>
            <p className="text-3xl font-black text-orange-400">{topScore || "—"}</p>
          </div>
          <div className="bg-gray-900/80 backdrop-blur border border-gray-800 rounded-2xl px-6 py-4 min-w-[140px]">
            <p className="text-gray-500 text-xs mb-1">👑 Legend</p>
            <p className="text-3xl font-black text-red-400 truncate max-w-[120px]">{topPlayer}</p>
          </div>
        </div>

        {/* CTA Buttons */}
        <div className="flex justify-center gap-3 flex-wrap">
          <button
            onClick={() => setActiveTab("add")}
            className="px-6 py-3 bg-gradient-to-r from-yellow-500 to-orange-500 text-gray-900 font-bold rounded-xl hover:opacity-90 transition text-sm"
          >
            ➕ Add Player
          </button>
          <button
            onClick={() => setActiveTab("leaderboard")}
            className="px-6 py-3 bg-gray-800 border border-gray-700 text-white font-bold rounded-xl hover:bg-gray-700 transition text-sm"
          >
            🏆 View Rankings
          </button>
        </div>
      </div>
    </div>
  );
}

export default function App() {
  const [activeTab, setActiveTab] = useState("leaderboard");

  const tabs = [
    { id: "leaderboard", label: "🏆 Leaderboard" },
    { id: "add", label: "➕ Add" },
    { id: "remove", label: "🗑️ Remove" },
    { id: "stats", label: "📊 Stats" },
    { id: "performance", label: "⚡ Performance" },
    { id: "history", label: "📜 History" },
  ];

  return (
    <QueryClientProvider client={queryClient}>
      <div className="min-h-screen bg-gray-950 text-white">

        {/* Hero */}
        <HeroSection setActiveTab={setActiveTab} />

        {/* Tabs */}
        <div className="flex justify-center gap-2 mt-6 px-4 flex-wrap">
          {tabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`px-4 py-2 rounded-full text-sm font-medium transition-all duration-200 ${
                activeTab === tab.id
                  ? "bg-yellow-500 text-gray-900 shadow-lg shadow-yellow-500/30"
                  : "bg-gray-800 text-gray-400 hover:bg-gray-700"
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>

        {/* Content */}
        <div className="max-w-4xl mx-auto px-4 py-8">
          {activeTab === "leaderboard" && <Leaderboard />}
          {activeTab === "add" && <AddEntry />}
          {activeTab === "remove" && <RemoveEntry />}
          {activeTab === "stats" && <StatsPanel />}
          {activeTab === "performance" && <PerformancePanel />}
          {activeTab === "history" && <HistoryPanel />}
        </div>
      </div>
    </QueryClientProvider>
  );
}
